class Solution:
    def findMaxSum(self, nums1, nums2, k):
        n = len(nums1)
        ans = []
        for i in range(n):
            vals = sorted((nums2[j] for j in range(n) if nums1[j] < nums1[i]), reverse=True)
            ans.append(sum(vals[:k]))
        return ans

