var findMaxSum = function(nums1, nums2, k) {
    const n = nums1.length;
    const order = Array.from({ length: n }, (_, i) => i).sort((a, b) => nums1[a] - nums1[b]);
    const ans = new Array(n).fill(0);
    const heap = [];
    let total = 0;
    const pushHeap = (v) => {
        heap.push(v);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p] <= heap[i]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const popHeap = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            for (;;) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < heap.length && heap[l] < heap[s]) s = l;
                if (r < heap.length && heap[r] < heap[s]) s = r;
                if (s === i) break;
                [heap[s], heap[i]] = [heap[i], heap[s]];
                i = s;
            }
        }
        return top;
    };
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && nums1[order[j]] === nums1[order[i]]) j++;
        const group = order.slice(i, j);
        for (const idx of group) ans[idx] = total;
        for (const idx of group) {
            const v = nums2[idx];
            pushHeap(v);
            total += v;
            if (heap.length > k) {
                total -= popHeap();
            }
        }
        i = j;
    }
    return ans;
};
